sp_angular_provider.script:
/* Use this Directive to add icons for the suspense date and have a table cell with a hover popover function
Note: AngularJS normalizes case-sensitive camelCase to case-insensitive kebab-case for the DOM.
Usage in a widget's HTML:
	<dtech-duration dtech-assigned-member="{{item.assigned_to.display_value}}"
		dtech-duration-modal-title = "{{item.duration_modal_title}}"
        dtech-is-modal="data.isModal"
        dtech-number="{{item.comment_number}}"
        dtech-status-reason="{{item.status_reason}}"
        dtech-status="{{item.duration_status}}"
        dtech-short-description="{{item.task_name}}"
        dtech-suspense-date="{{item.duration_suspense_date}}"
        dtech-show-long-dates="{{data.showLongDates}}"
        dtech-state="{{item.comment_state}}"
        table="{{data.table}}"
        task-sys-id="{{item.sys_id}}">
	</dtech-duration>


	The HTML for the directive is in	
	templateUrl: getTemplateUrl('x_153465_discovert_dtechDuration.html')
//
// Copyrights belong to Discover Technologies LLC. © 2023 Discover Technologies LLC
// Script Continued Below
// 2.8.1 | 2023-04-07 | raj | STRY0137371 - Icons to Represent Status
//  Created Directive								   
*/
function dtechDuration(getTemplateUrl, spModal, $timeout, $window) {
	var CONST_TEMP_WAIT_DURATION = 600;
	var dtUser = {
		restrict: 'E',
		replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way
		scope: {
			dtechAssignedMember: '@',
			dtechDurationModalTitle: '@',
			dtechDurationObject: "=",
			dtechIsModal: "=",
			dtechNumber: '@',
			dtechShortDescription: '@',
			dtechShowLongDates: '@',
			dtechStatus: '@',
			dtechStatusReason: '@',
			dtechState: '@',
			dtechSuspenseDate: '@',
			table: '@',
			taskSysId: '@'
		},
		controller: userCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechDuration.html')
	};
	return dtUser;

	function userCtrl($scope, $attrs, $animate, dtechTaskService) {
		var d = this;	
		d._isOverTooltip = false;
		d.dtechDurationToolTipOpen = _dtechDurationToolTipOpen;

		// passed in data section
		d.dtechAssignedMember = _dtechAssignedMember;
		d.dtechDurationModalTitle = _dtechDurationModalTitle;
		d.dtechIsModal = _dtechIsModal;
		d.dtechNumber = _dtechNumber;
		d.dtechShortDescription = _dtechShortDescription;
		d.dtechShowLongDates = _dtechShowLongDates;
		d.dtechStatus = _dtechStatus;
		d.dtechState = _dtechState;
		d.dtechStatusReason = _dtechStatusReason;
		d.dtechSuspenseDate = _dtechSuspenseDate;
		// directive's functional section
		d.enterTooltip = _enterTooltip;
		d.init = _init;
		d.leaveTooltip = _leaveTooltip;
		d.openModal= _openModal;
		d.parentMouseLeave = _parentMouseLeave;
		d.showDuration = _showDuration;

		function _dtechAssignedMember() {
			return $scope.dtechAssignedMember;
		}

		function _dtechDurationModalTitle() {
			return $scope.dtechDurationModalTitle;
		}

		function _dtechIsModal() {
			return $scope.dtechIsModal;
		}

		function _dtechNumber() {
			return $scope.dtechNumber;
		}

		function _dtechStatus() {
			return $scope.dtechStatus;
		}

		function _dtechSuspenseDate() {
			return $scope.dtechSuspenseDate;
		}

		function _dtechShortDescription() {
			return $scope.dtechShortDescription;
		}

		function _dtechShowLongDates() {
			return $scope.dtechShowLongDates;
		}

		function _dtechState() {
			return $scope.dtechState;
		}

		function _dtechStatusReason() {
			return $scope.dtechStatusReason;
		}

		function _dtechDurationToolTipOpen(){
			return $scope.dtechDurationToolTipOpen;
		}

		// when the user hovers over the tooltip set overtooltip flag
		function _enterTooltip() {
			d._isOverTooltip = true;
		}

		// init()
		// initialize the control, called from the Link function
		// gets a reference to the element
		function _init(element) {

			d.$element = element;

			$scope.dtechDurationToolTipOpen = 
				angular.isDefined($attrs.enterTooltip) ?
				$scope.$parent.$eval($attrs.dtechDurationToolTipOpen) : false;
		}

		function _leaveTooltip() {
			d._isOverTooltip = false;
			$scope.dtechDurationToolTipOpen = false;
		}

		// openModal()
		// this function is called from Template html
		// it is called when a user clicks on the open link
		function _openModal(event) {
			var title = $scope.dtechDurationModalTitle;
			x_153465_discovert.twJS.openDurationModal(spModal, title, $scope.table, $scope.taskSysId);
			event.stopPropagation();
		}

		// _parentMouseLeave
		// this is the get function for the direcitve property parentMouseLeave
		// this function is called when the user hovers off the profile image
		function _parentMouseLeave() {
			$timeout(function() {
				if(!d._isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_DURATION);
		}

		function _showDuration(event) {
			$scope.dtechDurationToolTipOpen = true;
			var durationObject = $scope.dtechDurationObject;
			if(!durationObject){
				durationObject = {};
				durationObject.taskId = $scope.taskSysId;
				durationObject.loaded = false;
			}
			if(!durationObject.loaded){
				d.isSpinnerShown = true;
				dtechTaskService.getDurationInformation($scope.taskSysId).then(
					function(response){
						$scope.dtechDurationObject = response.durationInformation;
						d.isSpinnerShown = false;
						$scope.dtechDurationObject.loaded = true;
					});
			}
			$scope.dtechDurationObject=durationObject;
			$scope.dtechDurationToolTipOpen = true;
		}		
	} // end function userCtrl

	// Link function links local methods to parent controller methods
	// see the list of events being monitored
	function link(scope, element, attrs, userCtrl) {
		// initialize the control
		userCtrl.init(element);			
		scope.$on('$destroy',_destroy);
		// get the location of the element hovering over

		function _destroy() {
			element.remove();
		}
	}

}
